30	// ListModels returns models matching the filter, with full metadata.
31	// Empty filter returns all models from every reachable provider.
32	func (s *service) ListModels(ctx context.Context, filter ModelFilter) ([]ModelInfo, error) {
33		if filter.Harness != "" && harnesses.ResolveHarnessAlias(filter.Harness) != "fiz" {
34			return s.listModelsForSubprocessHarness(filter), nil
35		}
36	
37		sc := s.opts.ServiceConfig
38		if sc == nil {
39			return nil, fmt.Errorf("service: no ServiceConfig provided; pass ServiceOptions.ServiceConfig")
40		}
41	
42		// Load the model catalog once for cross-referencing.
43		cat, _ := modelcatalog.Default() // ignore error: catalog miss is non-fatal
44		cacheRoot, err := serviceSnapshotCacheRoot()
45		if err != nil {
46			return nil, err
47		}
48		snapshot, err := assembleModelSnapshotFromServiceConfigWithOptions(ctx, sc, cat, cacheRoot, modelsnapshot.AssembleOptions{Refresh: modelsnapshot.RefreshForce})
49		if err != nil {
50			return nil, err
51		}
52		return s.listModelsFromSnapshot(ctx, sc, cat, snapshot, filter), nil
53	}
