91	func subprocessHarnessModelIDs(name string, cfg harnesses.HarnessConfig) []string {
92		models := append([]string(nil), cfg.Models...)
93		switch name {
94		case "claude":
95			snapshot := claudeharness.DefaultClaudeModelDiscovery()
96			models = appendUniqueModelIDs(models, snapshot.Models...)
97			for _, family := range []string{"sonnet", "opus", "haiku"} {
98				resolved := claudeharness.ResolveClaudeFamilyAlias(family, snapshot)
99				if resolved != family {
100					models = appendUniqueModelIDs(models, resolved)
101				}
102			}
103		case "codex":
104			snapshot := codexharness.DefaultCodexModelDiscovery()
105			models = appendUniqueModelIDs(models, snapshot.Models...)
106			for _, family := range []string{"gpt", "gpt-5"} {
107				resolved := codexharness.ResolveCodexModelAlias(family, snapshot)
108				if resolved != family {
109					models = appendUniqueModelIDs(models, resolved)
110				}
111			}
112		case "gemini":
113			snapshot := geminiharness.DefaultGeminiModelDiscovery()
114			models = appendUniqueModelIDs(models, snapshot.Models...)
115			for _, family := range []string{"gemini", "gemini-2.5"} {
116				resolved := geminiharness.ResolveGeminiModelAlias(family, snapshot)
117				if resolved != family {
118					models = appendUniqueModelIDs(models, resolved)
119				}
120			}
121		}
122		return models
123	}
