125	func resolveSubprocessModelAlias(harness, model string) string {
126		switch harness {
127		case "claude":
128			return claudeCLIExecutableModel(model)
129		case "codex":
130			return codexharness.ResolveCodexModelAlias(model, codexharness.DefaultCodexModelDiscovery())
131		case "gemini":
132			return geminiharness.ResolveGeminiModelAlias(model, geminiharness.DefaultGeminiModelDiscovery())
133		default:
134			return model
135		}
136	}
