152	func appendUniqueModelIDs(values []string, additions ...string) []string {
153		for _, value := range additions {
154			value = strings.TrimSpace(value)
155			if value == "" {
156				continue
157			}
158			found := false
159			for _, existing := range values {
160				if existing == value {
161					found = true
162					break
163				}
164			}
165			if !found {
166				values = append(values, value)
167			}
168		}
169		return values
170	}
