172	func (s *service) listModelsFromSnapshot(ctx context.Context, sc ServiceConfig, cat *modelcatalog.Catalog, snapshot modelsnapshot.ModelSnapshot, filter ModelFilter) []ModelInfo {
173		defaultProviderName := sc.DefaultProviderName()
174		entries := make(map[string]ServiceProviderEntry, len(sc.ProviderNames()))
175		for _, name := range sc.ProviderNames() {
176			if filter.Provider != "" && filter.Provider != name {
177				continue
178			}
179			entry, ok := sc.Provider(name)
180			if !ok {
181				continue
182			}
183			entries[name] = entry
184		}
185	
186		modelsByProvider := make(map[string][]modelsnapshot.KnownModel, len(snapshot.Models))
187		for _, model := range snapshot.Models {
188			if filter.Provider != "" && filter.Provider != model.Provider {
189				continue
190			}
191			if _, ok := entries[model.Provider]; !ok {
192				continue
193			}
194			modelsByProvider[model.Provider] = append(modelsByProvider[model.Provider], model)
195		}
196	
197		rankByEndpoint := make(map[string]int, len(snapshot.Models))
198		out := make([]ModelInfo, 0, len(snapshot.Models))
199		for _, providerName := range sc.ProviderNames() {
200			if filter.Provider != "" && filter.Provider != providerName {
201				continue
202			}
203			entry, ok := entries[providerName]
204			if !ok {
205				continue
206			}
207			for _, model := range modelsByProvider[providerName] {
208				normalizedModel := model
209				normalizedModel.ServerInstance = serverinstance.Normalize(model.EndpointBaseURL, model.ServerInstance)
210				rankKey := strings.Join([]string{normalizedModel.Provider, normalizedModel.EndpointName, normalizedModel.EndpointBaseURL, normalizedModel.ServerInstance}, "\x00")
211				rank := rankByEndpoint[rankKey]
212				rankByEndpoint[rankKey] = rank + 1
213				out = append(out, s.modelInfoFromSnapshotModel(ctx, providerName, entry, defaultProviderName, cat, normalizedModel, rank))
214			}
215		}
216		return out
217	}
