306	// resolveContextEvidence resolves the context window for a model using the
307	// precedence chain: provider config > provider API > catalog > default.
308	func resolveContextEvidence(ctx context.Context, entry ServiceProviderEntry, modelID string, cat *modelcatalog.Catalog) (int, string) {
309		modelID = strings.TrimSpace(modelID)
310		if modelID == "" {
311			return 0, ContextSourceUnknown
312		}
313		if entry.ContextWindow > 0 {
314			return entry.ContextWindow, ContextSourceProviderConfig
315		}
316		if limits, source := providerAPIContextEvidence(ctx, entry, modelID); limits > 0 {
317			return limits, source
318		}
319		if cat != nil {
320			if n := cat.ContextWindowForModel(modelID); n > 0 {
321				return n, ContextSourceCatalog
322			}
323		}
324		return compaction.DefaultContextWindow, ContextSourceDefault
325	}
