90	// refreshQuotaLocked is the single-flight critical section. It probes
91	// PTY, writes the cache on success, and returns the projected status.
92	// Probe failure is folded into State=QuotaUnavailable.
93	func (r *Runner) refreshQuotaLocked(ctx context.Context) harnesses.QuotaStatus {
94		now := time.Now()
95		timeout := geminiQuotaFreshness
96		if deadline, ok := ctx.Deadline(); ok {
97			remaining := time.Until(deadline)
98			if remaining > 0 && remaining < timeout {
99				timeout = remaining
100			}
101		}
102		var opts []QuotaPTYOption
103		if r.Binary != "" {
104			opts = append(opts, WithQuotaPTYCommand(r.Binary))
105		}
106		windows, _, err := captureGeminiQuotaViaPTY(ctx, timeout, opts...)
107		if err != nil {
108			state := harnesses.QuotaUnavailable
109			reason := err.Error()
110			lower := strings.ToLower(reason)
111			switch {
112			case strings.Contains(lower, "not found") || strings.Contains(lower, "executable file not found"):
113				state = harnesses.QuotaUnavailable
114			case strings.Contains(lower, "unauth") || strings.Contains(lower, "credential"):
115				state = harnesses.QuotaUnauthenticated
116			}
117			return harnesses.QuotaStatus{
118				Source:            "pty",
119				CapturedAt:        now.UTC(),
120				State:             state,
121				RoutingPreference: harnesses.RoutingPreferenceUnknown,
122				Reason:            reason,
123			}
124		}
125		account := ReadAuthEvidence(now).Account
126		snap := GeminiQuotaSnapshot{
127			CapturedAt: now.UTC(),
128			Windows:    windows,
129			Source:     "pty",
130			Account:    account,
131		}
132		if path, pathErr := GeminiQuotaCachePath(); pathErr == nil {
133			_ = WriteGeminiQuota(path, snap)
134		}
135		return geminiQuotaStatusFromSnapshot(&snap, now)
136	}
